class Solution {
public:
    int racecar(int target) {
        queue<pair<int, int>> q;
        unordered_set<string> vis;
        q.push({0, 1});
        vis.insert("0 1");
        int steps = 0;
        while (!q.empty()) {
            int size = q.size();
            for (int i = 0; i < size; i++) {
                auto [pos, speed] = q.front(); q.pop();
                if (pos == target) return steps;
                int newPosA = pos + speed, newSpeedA = speed * 2;
                string keyA = to_string(newPosA) + " " + to_string(newSpeedA);
                if (vis.find(keyA) == vis.end()) {
                    q.push({newPosA, newSpeedA});
                    vis.insert(keyA);
                }
                int newSpeedR = (speed > 0) ? -1 : 1;
                string keyR = to_string(pos) + " " + to_string(newSpeedR);
                if (vis.find(keyR) == vis.end()) {
                    q.push({pos, newSpeedR});
                    vis.insert(keyR);
                }
            }
            steps++;
        }
        return -1;
    }
};
```
